import urllib.request
import urllib.error
import json
import ipaddress
import ssl
from urllib.parse import urlparse


# Allowlist of permitted domains for enrichment URLs
ALLOWED_DOMAINS = {
    'api.example.com',
    'data.example.com',
    'enrichment.example.com',
}

# Maximum number of enrichment URLs to process
MAX_ENRICH_URLS = 3

# Timeout for HTTP requests (seconds)
REQUEST_TIMEOUT = 2

# Maximum response size (bytes)
MAX_RESPONSE_SIZE = 8192

# Allowed schemes
ALLOWED_SCHEMES = {'https'}


def is_private_ip(hostname):
    """Check if a hostname resolves to a private/reserved IP address to prevent SSRF."""
    try:
        import socket
        resolved_ips = socket.getaddrinfo(hostname, None)
        for entry in resolved_ips:
            ip = ipaddress.ip_address(entry[4][0])
            if (ip.is_private or ip.is_loopback or ip.is_reserved or
                    ip.is_link_local or ip.is_multicast or
                    ip.is_unspecified):
                return True
        return False
    except Exception:
        return True


def validate_url(url):
    """Validate that the URL is safe to fetch."""
    if not url or not isinstance(url, str):
        return False, "Invalid URL"

    if len(url) > 2048:
        return False, "URL too long"

    try:
        parsed = urlparse(url)
    except Exception:
        return False, "URL parsing failed"

    # Enforce HTTPS only
    if parsed.scheme not in ALLOWED_SCHEMES:
        return False, f"Scheme '{parsed.scheme}' not allowed. Only HTTPS permitted."

    # Ensure hostname is present
    if not parsed.hostname:
        return False, "No hostname in URL"

    # Check against domain allowlist
    hostname = parsed.hostname.lower().rstrip('.')
    if hostname not in ALLOWED_DOMAINS:
        return False, f"Domain '{hostname}' not in allowlist"

    # Block requests to private/internal IPs (SSRF protection)
    if is_private_ip(hostname):
        return False, "URL resolves to private/internal IP address"

    # Block URLs with credentials
    if parsed.username or parsed.password:
        return False, "URLs with embedded credentials not allowed"

    # Block non-standard ports
    if parsed.port and parsed.port != 443:
        return False, "Only port 443 allowed"

    # Block fragments and suspicious path traversal
    if '..' in parsed.path:
        return False, "Path traversal detected"

    return True, "OK"


def safe_fetch(url):
    """Safely fetch data from a validated URL with size limits and timeouts."""
    ssl_context = ssl.create_default_context()

    req = urllib.request.Request(
        url,
        method='GET',
        headers={
            'User-Agent': 'LambdaEdge-Enrichment/1.0',
            'Accept': 'application/json',
        }
    )

    try:
        response = urllib.request.urlopen(
            req,
            timeout=REQUEST_TIMEOUT,
            context=ssl_context
        )

        if response.status != 200:
            return None, f"HTTP {response.status}"

        # Read with size limit to prevent memory exhaustion
        data = response.read(MAX_RESPONSE_SIZE + 1)
        if len(data) > MAX_RESPONSE_SIZE:
            return None, "Response too large"

        content_type = response.headers.get('Content-Type', '')
        if 'application/json' not in content_type:
            return None, "Response is not JSON"

        parsed_data = json.loads(data.decode('utf-8'))
        return parsed_data, None

    except urllib.error.URLError as e:
        return None, f"URL error: {str(e)[:100]}"
    except json.JSONDecodeError:
        return None, "Invalid JSON response"
    except Exception as e:
        return None, f"Fetch error: {str(e)[:100]}"


def sanitize_header_value(value):
    """Sanitize a string for safe inclusion as a header value."""
    if not isinstance(value, str):
        value = str(value)
    # Remove newlines and carriage returns to prevent header injection
    value = value.replace('\r', '').replace('\n', '').replace('\x00', '')
    # Limit length for Lambda@Edge header size constraints
    if len(value) > 4096:
        value = value[:4096]
    return value


def lambda_handler(event, context):
    """
    Lambda@Edge viewer request handler that enriches requests with data
    fetched from URLs specified in the X-Enrich-URL header.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})

    # Extract enrichment URLs from headers
    enrich_url_headers = headers.get('x-enrich-url', [])

    if not enrich_url_headers:
        return request

    enrichment_results = {}
    errors = []
    urls_processed = 0

    for header_entry in enrich_url_headers:
        if urls_processed >= MAX_ENRICH_URLS:
            errors.append("Max enrichment URL limit reached")
            break

        url = header_entry.get('value', '').strip()

        # Validate the URL
        is_valid, validation_msg = validate_url(url)
        if not is_valid:
            errors.append(f"Rejected URL: {validation_msg}")
            continue

        # Re-resolve and check IP right before fetching (TOCTOU mitigation)
        hostname = urlparse(url).hostname
        if is_private_ip(hostname):
            errors.append("URL resolves to private IP on re-check")
            continue

        # Fetch data from the validated URL
        data, fetch_error = safe_fetch(url)
        urls_processed += 1

        if fetch_error:
            errors.append(f"Fetch failed: {fetch_error}")
            continue

        # Store result keyed by a sanitized version of the URL
        safe_key = urlparse(url).hostname
        enrichment_results[safe_key] = data

    # Remove the original enrichment header to prevent forwarding to origin
    if 'x-enrich-url' in headers:
        del headers['x-enrich-url']

    # Add enrichment data as a header for the origin
    if enrichment_results:
        enriched_json = json.dumps(enrichment_results, separators=(',', ':'))
        sanitized_value = sanitize_header_value(enriched_json)
        headers['x-enrichment-data'] = [{
            'key': 'X-Enrichment-Data',
            'value': sanitized_value
        }]

    # Add enrichment status header
    status = "success" if enrichment_results else "no_data"
    if errors:
        status = "partial" if enrichment_results else "failed"

    headers['x-enrichment-status'] = [{
        'key': 'X-Enrichment-Status',
        'value': sanitize_header_value(status)
    }]

    # Optionally include sanitized error info (limited)
    if errors:
        error_summary = "; ".join(errors[:3])
        headers['x-enrichment-errors'] = [{
            'key': 'X-Enrichment-Errors',
            'value': sanitize_header_value(error_summary[:512])
        }]

    request['headers'] = headers
    return request